          setIconState(!!event.data.isPlaying, !!event.data.hasMusic);

          var audio = document.getElementById('bgMusic') || document.getElementById('background-music');
          if (!audio) return;

          var source = audio.querySelector('source');
          if (event.data.src) {
            audio.setAttribute('src', event.data.src);
            if (source) source.setAttribute('src', event.data.src);
          }

          audio.pause();
          audio.currentTime = 0;
