          <button type="button" id="chrome-rsvp-submit" class="chrome-submit-btn" style="background: linear-gradient(90deg, #38bdf8, #0284c7); margin-top: 2px;" data-editable="rsvp-submit" ${c?"disabled":""}>${L}</button>
